def F(y):
print(y)
if(y < 2):
F(y + 1)
else:
print(y)
print(y)
請問以下程式，輸出結果為何？（8分）
#include <iostream>
using namespace std;
unsigned long long int fun(unsigned int n)
{
unsigned long long int x = 0;
unsigned long long int y = 1;
for (unsigned int j = 2; j <= n; ++j){
if (j % 2 == 0) x += y;
else y += x;
}
if(n % 2 == 0) return x;
else return y;
}
int main(){
int x = 5, y = 7;
cout << fun(x) << endl;
cout << fun(y);
}
